vector<int> resolveAsteroidCollisions(vector<int>& asteroidList) {
    stack<int> st;

    for (int a : asteroidList) {
        bool alive = true;

        while (alive && a < 0 && !st.empty() && st.top() > 0) {
            if (st.top() < -a) {
                st.pop();
            } else if (st.top() == -a) {
                st.pop();
                alive = false;
            } else {
                alive = false;
            }
        }

        if (alive) st.push(a);
    }

    vector<int> result;
    while (!st.empty()) {
        result.push_back(st.top());
        st.pop();
    }
    reverse(result.begin(), result.end());

    return result;
}

