#include <stdlib.h>

/**
 * Note: The returned array must be malloced, assume caller calls free().
 * returnSize is used to let the caller know the size of the returned array.
 */
int* resolveAsteroidCollisions(int* asteroidList, int size, int* returnSize) {
    // Allocate maximum possible size for the stack (if no collisions happen)
    int* stack = (int*)malloc(size * sizeof(int));
    int top = -1;

    for (int i = 0; i < size; i++) {
        int val = asteroidList[i];
        int survived = 1; // Flag to track if the current asteroid survives

        // While current asteroid moves Left (-) and top of stack moves Right (+)
        while (val < 0 && top >= 0 && stack[top] > 0) {
            if (stack[top] < -val) {
                // Stack's asteroid is smaller, it explodes.
                // Current left-moving asteroid continues checking.
                top--; 
            } else if (stack[top] == -val) {
                // Both are the same size, both explode.
                top--; 
                survived = 0; 
                break; 
            } else {
                // Stack's asteroid is larger, current left-moving one explodes.
                survived = 0; 
                break;
            }
        }

        // If it survived all potential collisions, add it to the stack
        if (survived) {
            stack[++top] = val;
        }
    }

    // Set the size of the resulting array for the judge/caller
    *returnSize = top + 1;

    return stack;
}

