public int[] resolveAsteroidCollisions(int[] asteroidList) {
    int n = asteroidList.length, index = 0;
    int[] stack = new int[n];
    for (int asteroid : asteroidList) {
        boolean alive = true;
        while (alive && index > 0 && stack[index - 1] > 0 && asteroid < 0) {
            if (stack[index - 1] < -asteroid) {
                index--;
            } else if (stack[index - 1] == -asteroid) {
                index--;
                alive = false;
            } else {
                alive = false;
            }
        }
        if (alive) stack[index++] = asteroid;
    }
    int[] result = new int[index];
    System.arraycopy(stack, 0, result, 0, index);
    return result;
}

