function resolveAsteroidCollisions(asteroidList) {
  const stack = [];
  for (const asteroid of asteroidList) {
    let destroyed = false;
    while (
      stack.length &&
      asteroid < 0 &&
      stack[stack.length - 1] > 0
    ) {
      const top = stack[stack.length - 1];
      if (top < -asteroid) {
        stack.pop();
        continue;
      } else if (top === -asteroid) {
        stack.pop();
      }
      destroyed = true;
      break;
    }
    if (!destroyed) stack.push(asteroid);
  }
  return stack;
}
